-- ----------------------------
-- Table structure for offers
-- ----------------------------
DROP TABLE IF EXISTS `offers`;
CREATE TABLE `offers`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Teklif Id si',
  `productId` int NULL DEFAULT NULL COMMENT 'Ürün Id si',
  `userId` int NULL DEFAULT NULL COMMENT 'Teklifi veren kullanıcın id si',
  `offerHead` varchar(255) CHARACTER SET utf8 COLLATE utf8_turkish_ci NULL DEFAULT NULL COMMENT 'Teklif açıklaması',
  `offerValue` varchar(255) CHARACTER SET utf8 COLLATE utf8_turkish_ci NULL DEFAULT NULL COMMENT 'Teklif para değeri',
  `offerCreateTime` datetime NULL DEFAULT NULL COMMENT 'Teklif Oluşturulma Tarihi',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `productId`(`productId`) USING BTREE,
  CONSTRAINT `offers_ibfk_1` FOREIGN KEY (`productId`) REFERENCES `products` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 124 CHARACTER SET = utf8 COLLATE = utf8_turkish_ci ROW_FORMAT = DYNAMIC;

