DROP TABLE IF EXISTS `productcategories`;
CREATE TABLE `productcategories`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Ürün Kategori Id si',
  `category` varchar(255) CHARACTER SET utf8 COLLATE utf8_turkish_ci NULL DEFAULT NULL COMMENT 'Ürün Kategori Değeri',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12 CHARACTER SET = utf8 COLLATE = utf8_turkish_ci ROW_FORMAT = DYNAMIC;

