-- Table structure for products
-- ----------------------------
DROP TABLE IF EXISTS `products`;
CREATE TABLE `products`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Ürün Id si',
  `categoryId` int NULL DEFAULT NULL COMMENT 'Ürünün bağlı olduğu kategori id si',
  `productName` varchar(255) CHARACTER SET utf8 COLLATE utf8_turkish_ci NULL DEFAULT NULL COMMENT 'Ürün adı',
  `offerCreateTime` datetime NULL DEFAULT NULL COMMENT 'Ürün Teklif Oluşturabilme Tarihi',
  `offerFinishedTime` datetime NULL DEFAULT NULL COMMENT 'Ürün teklif süre sonu tarihi',
  `productImage` varchar(255) CHARACTER SET utf8 COLLATE utf8_turkish_ci NULL DEFAULT NULL COMMENT 'Ürün resim alanı',
  `productDescription` text CHARACTER SET utf8 COLLATE utf8_turkish_ci NULL COMMENT 'Ürün açıklaması',
  `productSubDescription` text CHARACTER SET utf8 COLLATE utf8_turkish_ci NULL COMMENT 'Ürün alt açıklaması',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `categoryId`(`categoryId`) USING BTREE,
  CONSTRAINT `products_ibfk_1` FOREIGN KEY (`categoryId`) REFERENCES `productcategories` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 29 CHARACTER SET = utf8 COLLATE = utf8_turkish_ci ROW_FORMAT = DYNAMIC;

